import{_ as a,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"原力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/原力.md","filePath":"4.资源分区/5.能量池/原力.md"}'),o={name:"4.资源分区/5.能量池/原力.md"};function d(l,r,b,i,_,c){return t(),p("div",null,[...r[0]||(r[0]=[e("h1",{id:"原力",tabindex:"-1"},[n("原力 "),e("a",{class:"header-anchor",href:"#原力","aria-label":'Permalink to "原力"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"汹涌疾风022")])])],-1),s('<h1 id="原力-1" tabindex="-1">原力 <a class="header-anchor" href="#原力-1" aria-label="Permalink to &quot;原力&quot;">​</a></h1><p>原力</p><p>原力是一种存在于万物之中的超自然力量，它无处不在而无所在。原力的哲学性观念源于“气”或者“道”等禅意概念，因而超越了常理与凡人的认知。<br> 原力天然具有两面性：光明与黑暗<br> 原力的光明面象征着事物的存在、生长、发展，任何事物的存在与发生皆与光明原力息息相关。<br> 原力的黑暗面象征着事物的改变、矛盾、冲突，因而黑暗原力的存在是宇宙间循环所不可或缺的。<br> 光明与黑暗原力会相互生克：毁灭意味着复苏，苦痛意味着痊愈。。。生与死、存在与湮灭，彼此之间循环不息。</p><p>原力的性质：原力具有光明、中立、黑暗三种性质，在开启原力能量池时，通常会决定一个角色的原力性质。</p><p>原力性质通常会因为以下情况而变更：<br> 光明原力在进入亢奋异常点数的毁灭性后果后，原力性质会永久的转变为黑暗。<br> 黑暗原力在角色愿意舍弃自我生命而去拯救他人后，原力性质会永久的转变为中立。</p><p>原力的关键属性：感知+沉着（光明）/操控（中立）/力量（黑暗）</p><p>原力的基本用法：<br> 光明：角色在进行感知或者沉着属性检定时，支付1点原力，在这一检定上获得1点能量加值。<br> 中立：角色在进行感知或者沉着属性检定时，支付1点原力，在这一检定上获得1点能量加值。<br> 黑暗：花招动作支付1点原力，在这一轮内的攻击检定上获得2点亵渎加值。</p><p>恢复方式：<br> 1、每次长休息后，恢复所有原力<br> 2、在进行一次短休息后，恢复关键属性检定成功数点原力<br> 每日恢复的原力不超过能量池上限的三倍。</p><p>原力觉醒<br> 500<br> 角色开启原力能量池，性质为中立。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
